function safeDecode(s) {
  try {
    return decodeURIComponent(s);
  } catch {
    return s;
  }
}

function parseKeyPath(key) {
  // Examples:
  // "a" -> ["a"]
  // "a[b][c]" -> ["a","b","c"]
  // "filters[tag][]" -> ["filters","tag",""]
  const parts = [];
  const re = /([^\[\]]+)|\[(.*?)\]/g;
  let m;

  while ((m = re.exec(key)) !== null) {
    const part = m[1] !== undefined ? m[1] : (m[2] !== undefined ? m[2] : '');
    parts.push(part);
  }

  if (parts.length > 0 && parts[0] === '') parts.shift();
  return parts;
}

function assignPath(obj, path, value) {
  let cur = obj;

  for (let i = 0; i < path.length; i++) {
    const key = path[i];
    const isLast = i === path.length - 1;

    if (key === '') {
      // array push
      if (!Array.isArray(cur)) {
        // convert to array if needed
        cur = [];
      }
      if (isLast) {
        cur.push(value);
        return;
      } else {
        if (cur.length === 0 || typeof cur[cur.length - 1] !== 'object') {
          cur.push({});
        }
        cur = cur[cur.length - 1];
        continue;
      }
    }

    if (isLast) {
      if (cur[key] === undefined) {
        cur[key] = value;
      } else if (Array.isArray(cur[key])) {
        cur[key].push(value);
      } else {
        cur[key] = [cur[key], value];
      }
    } else {
      if (cur[key] === undefined || typeof cur[key] !== 'object') {
        // decide next container: array if next is '', else object
        cur[key] = path[i + 1] === '' ? [] : {};
      }
      cur = cur[key];
    }
  }
}

export default function parseQueryStringAdvanced(qs) {
  if (typeof qs !== 'string') return {};

  const raw = qs.startsWith('?') ? qs.slice(1) : qs;
  if (!raw) return {};

  const out = {};

  for (const part of raw.split('&')) {
    if (!part) continue;

    const eq = part.indexOf('=');
    const kRaw = eq === -1 ? part : part.slice(0, eq);
    const vRaw = eq === -1 ? '' : part.slice(eq + 1);

    const key = safeDecode(kRaw.replace(/\+/g, ' '));
    if (!key) continue;

    const val = safeDecode(vRaw.replace(/\+/g, ' '));

    const path = parseKeyPath(key);
    if (path.length === 0) continue;

    assignPath(out, path, val);
  }

  return out;
}
